, 	"use strict";

// 生成器函数
function* generateSequence() {
  yield 1;
  yield 2;
  return 3;
}

// "生成器函数"创建了一个"生成器对象"
let generator = generateSequence();
// 关键点: 生成器对象是可迭代的
alert(generator); // [object Generator]

// 使用 for...of 遍历
let sequence = [0, ...generateSequence()];
alert(sequence); // 0, 1, 2, 3

// 使用解构
let [a, b, c] = generateSequence();
alert(a); // 1
alert(b); // 2
alert(c); // 3

// 使用 Array.from
let arr = Array.from(generateSequence());
alert(arr); // 1, 2, 3

// 使用 next() 手动迭代
let generator2 = generateSequence();
alert(generator2.next()); // {value: 1, done: false}
alert(generator2.next()); // {value: 2, done: false}
alert(generator2.next()); // {value: 3, done: true}
alert(generator2.next()); // {value: undefined, done: true}

// 生成器函数可以接收参数
function* generateSequenceWithStart(start) {
  yield start;
  yield start + 1;
  return start + 2;
}

let generator3 = generateSequenceWithStart(10);
alert(generator3.next()); // {value: 10, done: false}
alert(generator3.next()); // {value: 11, done: false}
alert(generator3.next()); // {value: 12, done: true}

